-- Migración 018: Tabla plana para la página Services (pageId=services).
-- 2 filas: locale 'en' y 'es'. Misma estructura que Rates, What to Expect: API content.php GET/PUT pageId=services.
--
-- ========== QUÉ HACER ANTES DE IMPLEMENTAR ==========
-- 1. Ejecutar este script en la misma BD que usa public/api/content.php.
-- 2. El INSERT incluye datos reales extraídos de page_content (export). Para regenerar:
--      node scripts/migrations/extract-services-json.js "C:\Users\augus\Downloads\page_content-last-downloaded.json"
--    y opcionalmente ejecutar el 018_seed_services_from_export.sql generado.
--
-- ========== DE DÓNDE SE TOMAN LOS DATOS PARA INSERTAR ==========
-- Los datos se extraen de la tabla page_content: la fila con page_id = 'services' tiene una columna content (JSON)
-- con toda la estructura: hero, quickJump, immigrationEvaluation, intro, categories, conditionsSection, ctaSection.
-- El script extract-services-json.js lee un export de page_content, localiza esa fila, y genera por idioma (en/es)
-- los valores para cada columna de page_services (textos localizados y JSON por locale).
--
-- ========== QUÉ TIENE LA PÁGINA DE SERVICIOS ==========
-- - Hero: título, subtítulo, imagen de fondo, alt (igual que Rates/Services actual).
-- - SEO: title, description.
-- - quickJump: texto del enlace "Quick jump" (opcional).
-- - immigrationEvaluation: texto del enlace a evaluaciones de inmigración.
-- - intro: texto de introducción sobre la cuadrícula de servicios.
-- - categories: array de categorías; cada una tiene id, title, y services[] (id, name, description, icon).
-- - conditionsSection: título, subtítulo, conditions[] (id, name, description, icon, link; opcionales imageUrl, detailIntro, detailContent para imagen e info detallada por condición).
-- - ctaSection: título, subtítulo, primaryCTAs[], secondaryCTA (botones al final de la página).
--
-- meta.lastUpdated: rellenar en ISO 8601 para evitar ZodError (ver PATRON-CONTENIDO-DESDE-BD).
-- Ejecutar en la misma BD que public/api/content.php (phpMyAdmin o CLI).

CREATE TABLE IF NOT EXISTS page_services (
  id INT AUTO_INCREMENT PRIMARY KEY,
  locale VARCHAR(5) NOT NULL UNIQUE COMMENT 'en or es',
  meta_last_updated VARCHAR(32),
  meta_version INT DEFAULT 1,
  seo_title VARCHAR(255) DEFAULT '',
  seo_description TEXT,
  hero_title VARCHAR(255) NOT NULL DEFAULT 'Services',
  hero_subtitle VARCHAR(500) DEFAULT '',
  hero_background_image VARCHAR(500) DEFAULT '',
  hero_background_image_alt VARCHAR(255) DEFAULT '',
  quick_jump_text TEXT COMMENT 'Quick jump link text for this locale',
  immigration_evaluation_text TEXT COMMENT 'Immigration evaluations link text for this locale',
  intro_text TEXT COMMENT 'Intro text above services grid for this locale',
  categories_json LONGTEXT NOT NULL COMMENT 'JSON array: [{ id, title, services: [{ id, name, description, icon }] }] for this locale',
  conditions_section_json LONGTEXT NOT NULL COMMENT 'JSON: { title, subtitle, conditions: [{ id, name, description, icon, link, imageUrl?, detailTitle?, detailContent? }] } for this locale; detailTitle = titulo detalle (ej. Understanding Anxiety), detailContent = descripcion larga; imageUrl = imagen opcional',
  cta_section_json LONGTEXT NOT NULL COMMENT 'JSON: { title, subtitle, primaryCTAs, secondaryCTA } for this locale',
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- INSERT con datos reales desde export page_content (extract-services-json.js).
INSERT INTO page_services (locale, meta_last_updated, meta_version, seo_title, seo_description, hero_title, hero_subtitle, hero_background_image, hero_background_image_alt, quick_jump_text, immigration_evaluation_text, intro_text, categories_json, conditions_section_json, cta_section_json) VALUES
('en', '2024-01-15T10:00:00Z', 1, 'Services - WholeSelf Counseling', 'Our comprehensive therapeutic services', 'Our Services', 'Comprehensive therapeutic support', '/uploads/hero/services.webp', 'Our Services - WholeSelf Counseling', 'Ready to book? Jump to consultation', 'Learn about Immigration Evaluations', 'Our services include, but not limited to, the following:', '[{"id":"evaluation--consultation","title":"Evaluation & Consultation","services":[{"id":"consultation","name":"Consultation","description":"Initial consultation to understand your needs.","icon":"ChatBubbleLeftRightIcon"},{"id":"psychiatric-evaluation","name":"Psychiatric Diagnostic Evaluation","description":"Comprehensive evaluation of mental health needs.","icon":"ClipboardDocumentCheckIcon"},{"id":"treatment-plan","name":"Treatment Plan Development","description":"Personalized plan aligned with your goals.","icon":"ClipboardDocumentListIcon"}]},{"id":"individual-psychotherapy","title":"Individual Psychotherapy","services":[{"id":"individual-psychotherapy","name":"Individual Psychotherapy","description":"One-on-one therapy tailored to your needs.","icon":"UserIcon"},{"id":"crisis-psychotherapy","name":"Psychotherapy for crisis","description":"Immediate support during difficult times.","icon":"ExclamationTriangleIcon"}]},{"id":"family--group-therapy","title":"Family & Group Therapy","services":[{"id":"family-without-patient","name":"Family Psychotherapy, without patient","description":"Support for family members without the patient present.","icon":"UsersIcon"},{"id":"family-conjoint","name":"Family Psychotherapy, conjoint psychotherapy, with patient present","description":"Family sessions with the patient present.","icon":"UserGroupIcon"},{"id":"group-psychotherapy","name":"Group Psychotherapy, other than multiple-family group","description":"Therapeutic groups for shared support and growth.","icon":"RectangleGroupIcon"},{"id":"couples-therapy","name":"Couples Therapy","description":"Support to strengthen communication and connection.","icon":"HeartIcon"}]},{"id":"support--community-services","title":"Support & Community Services","services":[{"id":"eap-session","name":"EAP Session","description":"Workplace mental health support through EAP.","icon":"BriefcaseIcon"},{"id":"peer-support","name":"Peer support services","description":"Support from people with lived experience.","icon":"HandRaisedIcon"},{"id":"community-support","name":"Comprehensive community support services","description":"Community-based support for overall well-being.","icon":"GlobeAmericasIcon"}]}]', '{"title":"Conditions We Support","subtitle":"We provide specialized support for various conditions. Click to learn more about our approach.","conditions":[{"id":"anxiety","name":"Anxiety Therapy","description":"Support for managing anxiety, panic, and worry through evidence-based approaches.","icon":"FaceFrownIcon","link":"/services/anxiety","detailTitle":"Understanding Anxiety","detailContent":"Anxiety is a natural response to stress, but when it becomes overwhelming or persistent, it can significantly impact your daily life. At Whole Self Counseling, we provide compassionate, evidence-based support to help you manage anxiety, panic, and worry.\n\nOur approach focuses on understanding your unique experience with anxiety and developing personalized strategies that work for you. We combine therapeutic techniques with practical tools to help you build resilience and regain control."},{"id":"adhd","name":"ADHD Support","description":"Comprehensive support for attention, focus, and executive function challenges.","icon":"AcademicCapIcon","link":"/services/adhd","detailTitle":"Understanding ADHD","detailContent":"ADHD (Attention-Deficit/Hyperactivity Disorder) affects attention, focus, and executive function in unique ways for each individual. At Whole Self Counseling, we provide comprehensive support to help you understand and work with your ADHD, rather than against it.\n\nOur approach focuses on building practical strategies, developing organizational skills, and creating systems that support your unique brain wiring. We help you harness your strengths while developing tools to manage challenges."},{"id":"depression","name":"Depression Treatment","description":"Evidence-based therapy to help you navigate depression and find hope again.","icon":"CloudIcon","link":"/services/depression","detailTitle":"Understanding Depression","detailContent":"Depression is more than feeling sad—it can affect every aspect of your life, from your energy levels to your relationships. At Whole Self Counseling, we provide evidence-based therapy to help you navigate depression and find hope again.\n\nOur compassionate approach focuses on understanding your unique experience, identifying patterns, and developing practical strategies for healing. We work together to build resilience, restore hope, and help you reconnect with what matters most to you."},{"id":"bipolar","name":"Bipolar Disorder Support","description":"Specialized support for managing mood cycles and building stability.","icon":"ArrowsUpDownIcon","link":"/services/bipolar","detailTitle":"Understanding Bipolar Disorder","detailContent":"Bipolar disorder involves cycles of mood changes that can range from depressive lows to manic or hypomanic highs. At Whole Self Counseling, we provide specialized support to help you manage these cycles and build stability in your life. Our approach focuses on recognizing early warning signs, developing coping strategies, and creating a support system that works for you. We help you understand your patterns, build routines that support stability, and develop skills to navigate both the highs and lows."},{"id":"trauma","name":"Trauma/PTSD Therapy","description":"Trauma-informed care to help you heal from past experiences and build resilience.","icon":"ShieldCheckIcon","link":"/services/trauma","detailTitle":"Understanding Trauma and PTSD","detailContent":"Trauma can leave lasting impacts on your mind, body, and spirit. Whether you''ve experienced a single traumatic event or ongoing trauma, healing is possible. At Whole Self Counseling, we provide trauma-informed care to help you heal from past experiences and build resilience.\n\nOur trauma-informed approach prioritizes safety, empowerment, and your pace of healing. We use evidence-based techniques to help you process traumatic memories, develop coping strategies, and rebuild a sense of safety and trust in yourself and others."},{"id":"stress","name":"Stress Management","description":"Tools and strategies to manage stress, build coping skills, and improve well-being.","icon":"FireIcon","link":"/services/stress","detailTitle":"Understanding Stress","detailContent":"Stress is a natural part of life, but when it becomes chronic or overwhelming, it can take a toll on your physical and mental health. At Whole Self Counseling, we provide tools and strategies to help you manage stress effectively and improve your overall well-being.\n\nOur approach focuses on identifying your unique stress triggers, developing healthy coping skills, and creating sustainable strategies for managing life''s challenges. We help you build resilience, set boundaries, and create a more balanced, fulfilling life."},{"id":"identity","name":"Identity/Transition Support","description":"Affirming support for gender identity, transition, and authentic self-expression.","icon":"UserCircleIcon","link":"/services/identity","detailTitle":"Understanding Identity and Transition","detailContent":"Exploring and affirming your gender identity is a deeply personal journey. At Whole Self Counseling, we provide affirming, supportive care for individuals navigating gender identity, transition, and authentic self-expression.\n\nOur approach is grounded in respect, validation, and empowerment. We create a safe, non-judgmental space where you can explore your identity at your own pace. We support you through all aspects of your journey, from self-discovery to social transition, helping you build confidence and live authentically."}]}', '{"title":"Ready to get started?","subtitle":"We''re here to support you on your healing journey.","primaryCTAs":[{"id":"help-me","title":"I need help","link":"/contact","color":"blueGreen"},{"id":"help-other","title":"My loved one needs help","link":"/contact","color":"navy"}],"secondaryCTA":{"id":"referral","title":"I need to make a referral","link":"/contact","text":"For healthcare providers and professionals"}}'),
('es', '2024-01-15T10:00:00Z', 1, 'Servicios - WholeSelf Counseling', 'Nuestros servicios terapéuticos integrales', 'Nuestros Servicios', 'Apoyo terapéutico integral', '/uploads/hero/services.webp', 'Nuestros Servicios - WholeSelf Counseling', '¿Listo para reservar? Ir a consulta', 'Conoce sobre Evaluaciones de Inmigración', 'Nuestros servicios incluyen, pero no se limitan a, lo siguiente:', '[{"id":"evaluacin-y-consulta","title":"Evaluación y Consulta","services":[{"id":"consultation","name":"Consulta","description":"Consulta inicial para entender tus necesidades.","icon":"ChatBubbleLeftRightIcon"},{"id":"psychiatric-evaluation","name":"Evaluación Diagnóstica Psiquiátrica","description":"Evaluación integral de tus necesidades de salud mental.","icon":"ClipboardDocumentCheckIcon"},{"id":"treatment-plan","name":"Desarrollo de Plan de Tratamiento","description":"Plan personalizado alineado con tus objetivos.","icon":"ClipboardDocumentListIcon"}]},{"id":"psicoterapia-individual","title":"Psicoterapia Individual","services":[{"id":"individual-psychotherapy","name":"Psicoterapia Individual","description":"Terapia individual adaptada a tus necesidades.","icon":"UserIcon"},{"id":"crisis-psychotherapy","name":"Psicoterapia para crisis","description":"Apoyo inmediato durante momentos difíciles.","icon":"ExclamationTriangleIcon"}]},{"id":"terapia-familiar-y-grupal","title":"Terapia Familiar y Grupal","services":[{"id":"family-without-patient","name":"Psicoterapia Familiar, sin paciente","description":"Apoyo a la familia sin el paciente presente.","icon":"UsersIcon"},{"id":"family-conjoint","name":"Psicoterapia Familiar, psicoterapia conjunta, con paciente presente","description":"Sesiones familiares con el paciente presente.","icon":"UserGroupIcon"},{"id":"group-psychotherapy","name":"Psicoterapia Grupal, distinta a grupo multifamiliar","description":"Terapia grupal para apoyo y crecimiento.","icon":"RectangleGroupIcon"},{"id":"couples-therapy","name":"Terapia de Pareja","description":"Apoyo para fortalecer comunicación y conexión.","icon":"HeartIcon"}]},{"id":"servicios-de-apoyo-y-comunitarios","title":"Servicios de Apoyo y Comunitarios","services":[{"id":"eap-session","name":"Sesión EAP","description":"Apoyo de salud mental laboral vía EAP.","icon":"BriefcaseIcon"},{"id":"peer-support","name":"Servicios de apoyo entre pares","description":"Apoyo de personas con experiencia vivida.","icon":"HandRaisedIcon"},{"id":"community-support","name":"Servicios integrales de apoyo comunitario","description":"Apoyo comunitario para tu bienestar.","icon":"GlobeAmericasIcon"}]}]', '{"title":"Condiciones que Apoyamos","subtitle":"Brindamos apoyo especializado para diversas condiciones. Haz clic para conocer más sobre nuestro enfoque.","conditions":[{"id":"anxiety","name":"Terapia para Ansiedad","description":"Apoyo para manejar ansiedad, pánico y preocupación mediante enfoques basados en evidencia.","icon":"FaceFrownIcon","link":"/services/anxiety","detailTitle":"Entendiendo la Ansiedad","detailContent":"La ansiedad es una respuesta natural al estrés, pero cuando se vuelve abrumadora o persistente, puede impactar significativamente tu vida diaria. En Whole Self Counseling, brindamos apoyo compasivo basado en evidencia para ayudarte a manejar la ansiedad, el pánico y la preocupación.\n\nNuestro enfoque se centra en entender tu experiencia única con la ansiedad y desarrollar estrategias personalizadas que funcionen para ti. Combinamos técnicas terapéuticas con herramientas prácticas para ayudarte a construir resiliencia y recuperar el control."},{"id":"adhd","name":"Apoyo para TDAH","description":"Apoyo integral para desafíos de atención, concentración y función ejecutiva.","icon":"AcademicCapIcon","link":"/services/adhd","detailTitle":"Entendiendo el TDAH","detailContent":"El TDAH (Trastorno por Déficit de Atención/Hiperactividad) afecta la atención, la concentración y la función ejecutiva de maneras únicas para cada individuo. En Whole Self Counseling, brindamos apoyo integral para ayudarte a entender y trabajar con tu TDAH, en lugar de luchar contra él.\n\nNuestro enfoque se centra en construir estrategias prácticas, desarrollar habilidades organizacionales y crear sistemas que apoyen tu cableado cerebral único. Te ayudamos a aprovechar tus fortalezas mientras desarrollas herramientas para manejar los desafíos."},{"id":"depression","name":"Tratamiento para Depresión","description":"Terapia basada en evidencia para ayudarte a navegar la depresión y encontrar esperanza nuevamente.","icon":"CloudIcon","link":"/services/depression","detailTitle":"Entendiendo la Depresión","detailContent":"La depresión es más que sentirse triste—puede afectar cada aspecto de tu vida, desde tus niveles de energía hasta tus relaciones. En Whole Self Counseling, brindamos terapia basada en evidencia para ayudarte a navegar la depresión y encontrar esperanza nuevamente.\n\nNuestro enfoque compasivo se centra en entender tu experiencia única, identificar patrones y desarrollar estrategias prácticas para la sanación. Trabajamos juntos para construir resiliencia, restaurar la esperanza y ayudarte a reconectar con lo que más te importa."},{"id":"bipolar","name":"Apoyo para Trastorno Bipolar","description":"Apoyo especializado para manejar ciclos de ánimo y construir estabilidad.","icon":"ArrowsUpDownIcon","link":"/services/bipolar","detailTitle":"Entendiendo el Trastorno Bipolar","detailContent":"El trastorno bipolar involucra ciclos de cambios de ánimo que pueden variar desde bajos depresivos hasta altos maníacos o hipomaníacos. En Whole Self Counseling, brindamos apoyo especializado para ayudarte a manejar estos ciclos y construir estabilidad en tu vida.\n\nNuestro enfoque se centra en reconocer signos de advertencia tempranos, desarrollar estrategias de afrontamiento y crear un sistema de apoyo que funcione para ti. Te ayudamos a entender tus patrones, construir rutinas que apoyen la estabilidad y desarrollar habilidades para navegar tanto los altos como los bajos."},{"id":"trauma","name":"Terapia para Trauma/TEPT","description":"Atención informada sobre trauma para ayudarte a sanar de experiencias pasadas y construir resiliencia.","icon":"ShieldCheckIcon","link":"/services/trauma","detailTitle":"Entendiendo el Trauma y el TEPT","detailContent":"El trauma puede dejar impactos duraderos en tu mente, cuerpo y espíritu. Ya sea que hayas experimentado un evento traumático único o trauma continuo, la sanación es posible. En Whole Self Counseling, brindamos atención informada sobre trauma para ayudarte a sanar de experiencias pasadas y construir resiliencia.\n\nNuestro enfoque informado sobre trauma prioriza la seguridad, el empoderamiento y tu ritmo de sanación. Usamos técnicas basadas en evidencia para ayudarte a procesar recuerdos traumáticos, desarrollar estrategias de afrontamiento y reconstruir un sentido de seguridad y confianza en ti mismo y en otros."},{"id":"stress","name":"Manejo del Estrés","description":"Herramientas y estrategias para manejar el estrés, desarrollar habilidades de afrontamiento y mejorar el bienestar.","icon":"FireIcon","link":"/services/stress","detailTitle":"Entendiendo el Estrés","detailContent":"El estrés es una parte natural de la vida, pero cuando se vuelve crónico o abrumador, puede afectar tu salud física y mental. En Whole Self Counseling, brindamos herramientas y estrategias para ayudarte a manejar el estrés efectivamente y mejorar tu bienestar general.\n\nNuestro enfoque se centra en identificar tus desencadenantes únicos de estrés, desarrollar habilidades de afrontamiento saludables y crear estrategias sostenibles para manejar los desafíos de la vida. Te ayudamos a construir resiliencia, establecer límites y crear una vida más equilibrada y satisfactoria."},{"id":"identity","name":"Apoyo para Identidad/Transición","description":"Apoyo afirmativo para identidad de género, transición y expresión auténtica del ser.","icon":"UserCircleIcon","link":"/services/identity","detailTitle":"Entendiendo la Identidad y la Transición","detailContent":"Explorar y afirmar tu identidad de género es un viaje profundamente personal. En Whole Self Counseling, brindamos atención afirmativa y de apoyo para personas que navegan la identidad de género, la transición y la expresión auténtica del ser.\n\nNuestro enfoque se basa en el respeto, la validación y el empoderamiento. Creamos un espacio seguro y sin juicios donde puedes explorar tu identidad a tu propio ritmo. Te apoyamos en todos los aspectos de tu viaje, desde el autodescubrimiento hasta la transición social, ayudándote a construir confianza y vivir auténticamente."}]}', '{"title":"¿Listo para comenzar?","subtitle":"Estamos aquí para apoyarte en tu camino de sanación.","primaryCTAs":[{"id":"help-me","title":"Necesito ayuda","link":"/contact","color":"blueGreen"},{"id":"help-other","title":"Mi ser querido necesita ayuda","link":"/contact","color":"navy"}],"secondaryCTA":{"id":"referral","title":"Necesito hacer una referencia","link":"/contact","text":"Para proveedores de salud y profesionales"}}')
ON DUPLICATE KEY UPDATE meta_last_updated=VALUES(meta_last_updated), meta_version=VALUES(meta_version), seo_title=VALUES(seo_title), seo_description=VALUES(seo_description), hero_title=VALUES(hero_title), hero_subtitle=VALUES(hero_subtitle), hero_background_image=VALUES(hero_background_image), hero_background_image_alt=VALUES(hero_background_image_alt), quick_jump_text=VALUES(quick_jump_text), immigration_evaluation_text=VALUES(immigration_evaluation_text), intro_text=VALUES(intro_text), categories_json=VALUES(categories_json), conditions_section_json=VALUES(conditions_section_json), cta_section_json=VALUES(cta_section_json), updated_at=NOW();
